// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKeyRaw = apiKeyHeader !== undefined ? headers[apiKeyHeader] : undefined;
const expectedKey = $env.WHISPER_API_KEY;

// Limit key length to prevent DoS via multi-megabyte payloads
const MAX_KEY_LENGTH = 256;
const providedKey = typeof providedKeyRaw === 'string' ? providedKeyRaw.slice(0, MAX_KEY_LENGTH) : '';

// Timing-safe comparison - constant time regardless of input length
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;
  if (a.length > MAX_LEN || b.length > MAX_LEN) return false;

  let result = 0;
  // Constant-time comparison: always iterate MAX_LEN, use 0 for out-of-bounds
  for (let i = 0; i < MAX_LEN; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  // Include length check in constant-time result (CRITICAL: prevents length oracle attacks)
  result |= (a.length === b.length) ? 0 : 1;
  return result === 0;
}

// CRITICAL: Always validate API key if provided, regardless of expectedKey
// This prevents fail-open vulnerability when env var is unset
// Authentication logic:
// - If server has expectedKey configured: client MUST provide matching key
// - If server has NO expectedKey configured: reject any request that provides a key (unauthorized)
// - If neither configured: allow (no auth required)
if ((expectedKey || providedKey) && !timingSafeEqual(providedKey || '', expectedKey || '')) {
  throw new Error('Authentication failed');
}

const input = $input.first().json || {};
const audio = input.audio || '';
const channelRaw = (input.channel || 'general').replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);

// === AUDIO VALIDATION ===
if (!audio || audio.trim().length === 0) {
  throw new Error('Missing required field: audio (base64)');
}
if (audio.length > 2097152) { // ~2MB base64 ≈ 1.5MB binary
  throw new Error('Audio too large: max ~2MB base64 encoded');
}

// === CHANNEL VALIDATION ===
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  throw new Error('Invalid channel: must be alphanumeric, dash, or underscore only');
}
const channel = channelRaw;

return [{
  json: {
    audio: audio.trim(),
    channel: channel
  }
}];

// Process transcription response
const body = $json;
const validatedInput = $('Validate Input').first().json || {};
const text = body.text || body.transcription || '';
const language = body.language || 'unknown';
const duration = body.duration || 0;

return [{
  json: {
    success: text.length > 0,
    language: language,
    duration_seconds: duration,
    character_count: text.length,
    transcript: text,
    timestamp: new Date().toISOString(),
    channel: validatedInput.channel || 'general'
  }
}];
